// A C program creating a child process via the fork() system call
#include <unistd.h>
int main() {
    pid_t pid = fork();      // system call into the kernel
    if (pid == 0)
        write(1, "child\n", 6);   // write() system call
    else
        write(1, "parent\n", 7);
    return 0;
}

